pub fn find(module: []const u8, name: []const u8) ?ApiRecord {
    for (records) |r| {
        if (std.mem.eql(u8, r.module, module) and std.mem.eql(u8, r.name, name)) return r;
    }
    return null;
}

pub fn countImplementedNameMatches() usize {
    var n: usize = 0;
    for (records) |r| {
        if (r.implemented_name_match) n += 1;
    }
    return n;
}

pub fn countModulePrefix(prefix: []const u8) usize {
    var n: usize = 0;
    for (records) |r| {
        if (std.mem.startsWith(u8, r.module, prefix)) n += 1;
    }
    return n;
}

pub fn countImplementedModulePrefix(prefix: []const u8) usize {
    var n: usize = 0;
    for (records) |r| {
        if (r.implemented_name_match and std.mem.startsWith(u8, r.module, prefix)) n += 1;
    }
    return n;
}

test "api surface manifest covers uploaded CuteDSL tree" {
    try std.testing.expect(records.len == source_record_count);
    try std.testing.expect(source_record_count >= 1300);
    try std.testing.expect(source_class_count >= 450);
    try std.testing.expect(source_function_count >= 850);
    try std.testing.expect(find("cutlass.cute.core", "make_layout") != null);
    try std.testing.expect(find("cutlass.cute.tensor", "TensorSSA") != null);
    try std.testing.expect(countImplementedNameMatches() >= 760);
}
